* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  background: #f0f2f5;
  color: #1a1a2e;
  line-height: 1.6;
}

.container {
  max-width: 800px;
  margin: 2rem auto;
  padding: 0 1rem;
}

h1 {
  text-align: center;
  font-size: 2rem;
  margin-bottom: 1.5rem;
  color: #16213e;
}

h2 {
  font-size: 1.2rem;
  margin-bottom: 1rem;
  color: #0f3460;
}

.card {
  background: #fff;
  border-radius: 12px;
  padding: 1.5rem;
  margin-bottom: 1.5rem;
  box-shadow: 0 2px 8px rgba(0,0,0,0.08);
}

.form-group {
  margin-bottom: 1rem;
}

.form-group label {
  display: block;
  font-size: 0.85rem;
  font-weight: 600;
  margin-bottom: 0.3rem;
  color: #555;
}

.form-row {
  display: flex;
  gap: 1rem;
  align-items: flex-end;
}

.form-row .form-group {
  flex: 1;
}

input[type="url"],
input[type="text"],
input[type="number"] {
  width: 100%;
  padding: 0.6rem 0.8rem;
  border: 2px solid #e0e0e0;
  border-radius: 8px;
  font-size: 0.95rem;
  transition: border-color 0.2s;
}

input:focus {
  outline: none;
  border-color: #533483;
}

.btn-primary {
  width: 100%;
  padding: 0.7rem;
  background: #533483;
  color: #fff;
  border: none;
  border-radius: 8px;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.2s;
}

.btn-primary:hover {
  background: #3a1f6b;
}

.btn-secondary {
  padding: 0.5rem 1rem;
  background: #e8e8e8;
  color: #333;
  border: none;
  border-radius: 8px;
  font-size: 0.9rem;
  cursor: pointer;
  transition: background 0.2s;
}

.btn-secondary:hover {
  background: #d0d0d0;
}

.btn-copy {
  background: none;
  border: none;
  font-size: 1.2rem;
  cursor: pointer;
  padding: 0.3rem;
}

.result {
  margin-top: 1rem;
  padding: 1rem;
  background: #e8f5e9;
  border-radius: 8px;
}

.result p {
  font-size: 0.85rem;
  color: #555;
  margin-bottom: 0.3rem;
}

.result-url {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.result-url a {
  font-size: 1.1rem;
  font-weight: 600;
  color: #2e7d32;
  word-break: break-all;
}

.error {
  margin-top: 0.8rem;
  padding: 0.8rem;
  background: #ffebee;
  color: #c62828;
  border-radius: 8px;
  font-size: 0.9rem;
}

.hidden {
  display: none;
}

table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 0.8rem;
  font-size: 0.85rem;
}

th {
  text-align: left;
  padding: 0.6rem 0.5rem;
  border-bottom: 2px solid #e0e0e0;
  color: #555;
  font-weight: 600;
}

td {
  padding: 0.5rem;
  border-bottom: 1px solid #f0f0f0;
}

td a {
  color: #533483;
  text-decoration: none;
}

td a:hover {
  text-decoration: underline;
}

.url-cell {
  max-width: 250px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.empty {
  text-align: center;
  color: #999;
  padding: 1.5rem;
}

.stats {
  margin-top: 1rem;
}

.stat-item {
  display: flex;
  justify-content: space-between;
  padding: 0.5rem 0;
  border-bottom: 1px solid #f0f0f0;
}

.stat-label {
  font-weight: 600;
  color: #555;
}

.stat-value {
  font-size: 1.3rem;
  font-weight: 700;
  color: #533483;
}

@media (max-width: 600px) {
  .form-row {
    flex-direction: column;
    gap: 0;
  }
}

